def solve(nums: Array[Long], k: Long): Long = {
  val n = nums.length
  val prefix_xor = Array.fill(n + 1)(0L)
  for (i <- 0 until n) {
    prefix_xor(i + 1) = prefix_xor(i) ^ nums(i)
  }

  var result = 0L
  var low = 0L
  var high = prefix_xor(n)

  while (low <= high) {
    val mid = (low + high) / 2
    var count = 1
    var current_xor = 0L
    for (i <- 0 until n) {
      current_xor ^= nums(i)
      if (current_xor == mid) {
        count += 1
        current_xor = 0L
      }
    }
    if (count >= k) {
      result = mid
      high = mid - 1
    } else {
      low = mid + 1
    }
  }

  result
}
